package com.promonts.repository;import com.promonts.domain.assignment.Assignment;import com.promonts.domain.course.Course;import org.springframework.data.jpa.repository.JpaRepository;import org.springframework.stereotype.Repository;import java.time.LocalDateTime;import java.util.List;@Repository public interface AssignmentRepository extends JpaRepository<Assignment, Long> { List<Assignment> findByCourse(Course course); List<Assignment> findByCourseAndDueDateAfter(Course course, LocalDateTime dueDate); List<Assignment> findByCourseCode(String courseCode); }
